DO $kim375$ DECLARE updated_count integer; BEGIN UPDATE "public"."reservations" SET "status" = 'cancelled'::"public"."reservation_status" WHERE "status" = 'pending'::"public"."reservation_status" AND "activated_at" IS NULL AND "created_at" < ("now"() - '01:00:00'::interval); LOOP WITH "loser" AS (SELECT "pending"."id" FROM "public"."reservations" AS "pending" WHERE "pending"."status" = 'pending'::"public"."reservation_status" AND "pending"."activated_at" IS NULL AND EXISTS (SELECT 1 FROM "public"."reservations" AS "kept" WHERE "kept"."id" <> "pending"."id" AND "kept"."table_id" = "pending"."table_id" AND "kept"."date" = "pending"."date" AND "kept"."status" = ANY (ARRAY['pending'::"public"."reservation_status", 'active'::"public"."reservation_status"]) AND "kept"."start_time" < "pending"."end_time" AND "kept"."end_time" > "pending"."start_time" AND ("kept"."surface" IS NULL OR "pending"."surface" IS NULL OR "kept"."surface" = "pending"."surface") AND ("kept"."status" = 'active'::"public"."reservation_status" OR "kept"."created_at" < "pending"."created_at" OR ("kept"."created_at" = "pending"."created_at" AND "kept"."id" < "pending"."id"))) ORDER BY "pending"."created_at" ASC, "pending"."id" ASC LIMIT 1) UPDATE "public"."reservations" SET "status" = 'cancelled'::"public"."reservation_status" WHERE "id" IN (SELECT "id" FROM "loser"); GET DIAGNOSTICS updated_count = ROW_COUNT; EXIT WHEN updated_count = 0; END LOOP; EXECUTE 'ALTER TABLE "public"."reservations" DROP CONSTRAINT IF EXISTS "reservations_no_pending_active_overlap_top"'; EXECUTE 'ALTER TABLE ONLY "public"."reservations" ADD CONSTRAINT "reservations_no_pending_active_overlap_top" EXCLUDE USING "gist" ("table_id" "extensions"."gist_uuid_ops" WITH =, "tsrange"(("date" + "start_time"), ("date" + "end_time"), ''[)''::"text") WITH &&) WHERE (("status" = ANY (ARRAY[''pending''::"public"."reservation_status", ''active''::"public"."reservation_status"])) AND ("surface" IS NULL OR "surface" = ''top''::"public"."table_sur